module RefModule(
    clock_2x,
    reset,
    dequeue_in,
    dequeue_out
);parameter N = 1;

    input           clock_2x;
    input           reset;
    input   [N-1:0] dequeue_in;
    output  [N-1:0] dequeue_out;

    reg obf_dequeue_cycle;

    always @(posedge clock_2x or posedge reset)
    begin
        if (reset)
            obf_dequeue_cycle = 1'b0;
        else
            obf_dequeue_cycle = ~obf_dequeue_cycle;
    end

    assign dequeue_out = {(N){obf_dequeue_cycle}} & dequeue_in;
endmodule
